#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#define MAX_N 20

// Check if 'next' vertex can be added after vertex 'v'
bool check(int v, int next, int* circuit, int circuitSize, bool mat[MAX_N][MAX_N]) {
    if (!mat[v][next]) // To check if v is adjacent to next
        return false;

    for (int i = 0; i < circuitSize; i++) { // To check if next is already visited
        if (circuit[i] == next)
            return false;
    }

    return true;
}

void backtrack(int v, int n, int* circuit, int circuitSize, int ans[MAX_N][MAX_N], int* ansSize, bool mat[MAX_N][MAX_N]) {
    if (circuitSize == n) { // Circuit is completed
        if (mat[circuit[0]][v]) { // Check if cycle is completed, starting should be adjacent to ending
            for (int i = 0; i < circuitSize; i++) {
                ans[*ansSize][i] = circuit[i];
            }
            ans[*ansSize][circuitSize] = circuit[0]; // Complete the circuit
            (*ansSize)++;
        }
        return;
    }

    for (int i = 1; i <= n; i++) {
        // Calling the check function
        if (!check(v, i, circuit, circuitSize, mat))
            continue;

        // If not visited and is adjacent, add it to our candidate solution
        circuit[circuitSize] = i;
        backtrack(i, n, circuit, circuitSize + 1, ans, ansSize, mat);
    }
}

// Number of vertices and adjacency matrix
void hamiltonian_circuit(int n, bool mat[MAX_N][MAX_N], int ans[MAX_N][MAX_N], int* ansSize) {
    int circuit[MAX_N]; // Initially empty circuit

    for (int i = 1; i <= n; i++) { // Fix the starting vertex
        circuit[0] = i; // Add i to circuit
        backtrack(i, n, circuit, 1, ans, ansSize, mat);
    }
}

// Function to compare two arrays for qsort
int compare(const void* a, const void* b) {
    const int* arr1 = (const int*)a;
    const int* arr2 = (const int*)b;
    for (int i = 0; i <= MAX_N; i++) {
        if (arr1[i] != arr2[i])
            return arr1[i] - arr2[i];
    }
    return 0;
}

// Function to print the solutions
void printSolutions(int ans[MAX_N][MAX_N], int ansSize, int n) {
    for (int i = 0; i < ansSize; i++) {
        for (int j = 0; j <= n; j++) { // Print the circuit with return to start
            printf("%d ", ans[i][j]);
        }
        printf("\n");
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while(t--) {
        int n, m;
        scanf("%d %d", &n, &m);

        // Adjacency matrix
        bool mat[MAX_N][MAX_N] = {false};
        while (m--) {
            int a, b;
            scanf("%d %d", &a, &b);
            mat[a][b] = true;
            mat[b][a] = true;
        }
        int ans[MAX_N][MAX_N] = {0};
        int ansSize = 0;

        hamiltonian_circuit(n, mat, ans, &ansSize);

        // Sort the solutions
        qsort(ans, ansSize, sizeof(ans[0]), compare);

        // Print the solutions
        printSolutions(ans, ansSize, n);
    }
    return 0;
}

