        if (mat[circuit[0]][v]) { // Check if cycle is completed, starting should be adjacent to ending
            circuit.push(circuit[0]);
            ans.push([...circuit]);
            circuit.pop();
        }
        return;
    }

    for (let i = 1; i <= n; i++) {
        // Calling the check function
